需要 ceil(n/k) 盒，花费 = ceil(n/k) * p。整数计算：(n + k - 1) / k * p。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, k, p;
    cin >> n >> k >> p;
    int boxes = (n + k - 1) / k;
    cout << boxes * p << endl;
    return 0;
}
```

由 e×d = (p-1)(q-1)+1 和 n=pq 得 m = n - e×d + 2 = p+q。解一元二次方程 x² - mx + n = 0，判别式 Δ = m²-4n，若 Δ < 0 或不是完全平方则无解。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int k;
    cin >> k;
    while (k--) {
        long long n, e, d;
        cin >> n >> d >> e;
        long long m = n - e * d + 2;
        long long delta = m * m - 4 * n;
        if (delta < 0) { cout << "NO" << endl; continue; }
        long long sq = sqrt(delta);
        if (sq * sq != delta) { cout << "NO" << endl; continue; }
        long long p = (m - sq) / 2, q = (m + sq) / 2;
        if (p * q != n || p <= 0 || q <= 0) { cout << "NO" << endl; continue; }
        cout << p << " " << q << endl;
    }
    return 0;
}
```

贪心：记录当前最低油价。到达站点 i 时，如果前方距离需要的油量超过当前油箱，以最低价补油。用优先队列或直接贪心模拟。

```cpp
#include <bits/stdc++.h>
using namespace std;
typedef long long ll;
int main() {
    int n;
    ll d;
    cin >> n >> d;
    vector<ll> v(n - 1);
    for (int i = 0; i < n - 1; i++) cin >> v[i];
    vector<ll> a(n);
    for (int i = 0; i < n; i++) cin >> a[i];
    ll cost = 0, fuel = 0, minPrice = a[0];
    for (int i = 0; i < n - 1; i++) {
        ll need = (v[i] + d - 1) / d;
        if (fuel < need) {
            ll buy = need - fuel;
            cost += buy * minPrice;
            fuel += buy;
        }
        fuel -= need;
        minPrice = min(minPrice, a[i + 1]);
    }
    cout << cost << endl;
    return 0;
}
```
